"$path = 'src/main/java/de/ajsch/villagerai/command/ChiefCommand.java'\n$content = Get-Content $path -Raw\n\n# Add SpeakerService import\nif ($content -notmatch 'import de.ajsch.villagerai.service.SpeakerService;') {\n    $content = $content -replace 'import de.ajsch.villagerai.model.Speaker;', 'import de.ajsch.villagerai.model.Speaker;`nimport de.ajsch.villagerai.service.SpeakerService;'\n}\n\n# Add SpeakerService field\nif ($content -notmatch 'private final SpeakerService speakerService;') {\n    $content = $content -replace 'private final ChiefService chiefService;', 'private final ChiefService chiefService;`n    private final SpeakerService speakerService;'\n}\n\n# Add SpeakerService to constructor params\n$content = $content -replace 'public ChiefCommand\(', 'public ChiefCommand('  # normalize\n\n# Add speakerService assignment after chiefService\n$content = $content -replace 'this.chiefService = chiefService;', 'this.chiefService = chiefService;`n        this.speakerService = speakerService;'\n\n# Replace getConversationSpeaker(villager) -> getSpeaker(villager).orElse(null)\n$content = $content -replace 'chiefService.getConversationSpeaker\(villager\)', 'speakerService.getSpeaker(villager).orElse(null)'\n\n# Replace .chatName() on speaker/chief types\n$content = $content -replace '\.chatName\(\)', '.displayName()'\n\n# Replace chiefService.createConversationProfile -> speakerService.createOrRefreshProfile\n$content = $content -replace 'chiefService.createConversationProfile', 'speakerService.createOrRefreshProfile'\n\n# Replace chiefService.isChief(villager)\n$content = $content -replace 'chiefService.isChief\(villager\)', 'speakerService.getSpeaker(villager).map(Speaker::isChief).orElse(false)'\n\n# Replace chiefService.getChief(villager) -> speakerService.getSpeaker(villager)\n$content = $content -replace 'chiefService.getChief\(villager\)', 'speakerService.getSpeaker(villager)'\n\n# Replace chiefService.findChiefByVillageId -> speakerService.findActiveChiefByVillageId\n$content = $content -replace 'chiefService.findChiefByVillageId', 'speakerService.findActiveChiefByVillageId'\n\n# Replace Optional<Chief> optionalChief with Optional<Speaker> optionalSpeaker\n$content = $content -replace 'Optional<Chief> optionalChief', 'Optional<Speaker> optionalSpeaker'\n$content = $content -replace 'optionalChief\.', 'optionalSpeaker.'\n\n# Replace Chief chief = chiefService.getConversationSpeaker -> Speaker speaker = speakerService.getSpeaker...\n$content = $content -replace 'Chief chief = chiefService.markChief', '__KEEP_CHIEF_MARK__'\n$content = $content -replace 'Chief chief', 'Speaker speaker'\n$content = $content -replace '__KEEP_CHIEF_MARK__', 'Chief chief'\n\n# Replace chief.villageId() / speakerId() etc - now handled by bulk replace\n# Replace remaining chief.chiefId() -> chief.speakerId() (was renamed)\n\nSet-Content $path $content -NoNewline\nWrite-Host 'ChiefCommand migration complete.'"